#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
int n;
long long f[N][2],ans;
bool to[N];
vector<int> g[N][2];
void dfs(int x){
	if(to[x])
		return;
	to[x]=1;
	f[x][1]=1;
	int len=g[x][0].size();
	for(int i=0;i<len;i++){
		int v=g[x][0][i];
		dfs(v),f[x][0]+=f[v][0]+f[v][1],f[x][1]+=f[v][1];
	}
	ans+=f[x][0];
	len=g[x][1].size();
	for(int i=0;i<len;i++)
		if(!to[g[x][1][i]]){
			int v=g[x][1][i];
			dfs(v);
		}
}
int main(){
	scanf("%d",&n);
	for(int i=1,u,v;i<n;i++){
		scanf("%d%d",&u,&v);
		g[u][0].push_back(v);
		g[v][1].push_back(u);
	}
	dfs(1);
	printf("%lld",ans);
	return 0;
}
